'use strict';
const AWS = require('aws-sdk');
const uuidv4 = require('uuid').v4;
const serverless = require('serverless-http');
AWS.config.update({region:'us-east-1'}); // Update your region here

// Define our DynamoDB table
var docClient = new AWS.DynamoDB.DocumentClient();
var params = {
  TableName: 'Users', // Update this with the name of your DynamoDB table
};

const express = require('express');
const app = express();
app.use(express.json());

// Define our REST API endpoint for user registration
app.post('/register', async (req, res) => {
  const email = req.body.email;
  const password = req.body.password;
  
  if (!email || !password) {
    return res.status(400).json({ error: 'Missing required fields' });
  }
  
  var params = {
      Item:{
          "id": uuidv4(),
          "email": email,
          "password": password // Don't store plaintext passwords in production code!
      },
      TableName:"Users"
  };

  try {
    await docClient.put(params).promise();
    res.status(201).json({ message: 'User registered successfully!' });
  } catch (err) {
    console.error('DynamoDB error: ', err);
    res.status(500).json({ error: 'Failed to register user' });
  }
});

module.exports.handler = serverless(app);